// Time:  O(n)
// Space: O(1)

class Solution {
public:
    int secondHighest(string s) {
        int first = -1, second = -1;
        for (const auto& c : s) {
            if (!isdigit(c)) {
                continue;
            }
            int d = c - '0';
            if (d > first) {
                second = first;
                first = d;
            } else if (first > d && d > second) {
                second = d;
            }
        }
        return second;
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def secondHighest(self, s):
        """
        :type s: str
        :rtype: int
        """
        first = second = -1
        for c in s:
            if not c.isdigit():
                continue
            d = int(c)
            if d > first:
                first, second = d, first
            elif first > d > second:
                second = d
        return second
